class Solution:
    def minSwaps(self, nums):
        def ds(x):
            s = 0
            while x:
                s += x % 10
                x //= 10
            return s
        n = len(nums)
        order = sorted(range(n), key=lambda i: (ds(nums[i]), nums[i]))
        dest = [0] * n
        for rank, idx in enumerate(order):
            dest[idx] = rank
        seen = [False] * n
        swaps = 0
        for i in range(n):
            if seen[i]:
                continue
            length = 0
            j = i
            while not seen[j]:
                seen[j] = True
                j = dest[j]
                length += 1
            swaps += length - 1
        return swaps

