var minSwaps = function(nums) {
    const ds = (x) => {
        let s = 0;
        while (x > 0) { s += x % 10; x = Math.floor(x / 10); }
        return s;
    };
    const n = nums.length;
    const order = Array.from({length: n}, (_, i) => i);
    order.sort((a, b) => {
        const da = ds(nums[a]), db = ds(nums[b]);
        if (da !== db) return da - db;
        return nums[a] - nums[b];
    });
    const dest = new Array(n);
    for (let rank = 0; rank < n; rank++) dest[order[rank]] = rank;
    const seen = new Array(n).fill(false);
    let swaps = 0;
    for (let i = 0; i < n; i++) {
        if (seen[i]) continue;
        let length = 0, j = i;
        while (!seen[j]) { seen[j] = true; j = dest[j]; length++; }
        swaps += length - 1;
    }
    return swaps;
};
